```csharp
using UnityEngine;

public class GroundCheck : MonoBehaviour
{
    public float groundCheckDistance = 0.1f;
    private bool isGrounded;

    void Update()
    {
        isGrounded = Physics2D.BoxCast(transform.position, new Vector2(0.1f, groundCheckDistance), 0, Vector2.down,groundCheckDistance);
        if (isGrounded)
        {
            transform.position = new Vector3(transform.position.x, transform.position.y + groundCheckDistance, transform.position.z);
        }
    }
}
