Voici un exemple de base :

```cpp
#include <unistd.h>
#include <iostream>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
    int fd[2];
    pipe(fd);

    pid_t pid = fork();

    if (pid < 0) {
        std::cerr << "fork failed" << std::endl;
        return 1;
    } else if (pid > 0) { // parent
        close(fd[1]); // fermer le descripteur d'écriture
        char buffer[100];
        int n = read(fd[0], buffer, 99);
        buffer[n] = '\0';
        std::cout << "Réponse du processus fils: " << buffer << std::endl;
        close(fd[0]); // fermer le descripteur de lecture
    } else { // fils
        close(fd[0]); // fermer le descripteur de lecture
        dup2(fd[1], STDOUT_FILENO); // rediriger la sortie de la console vers le descripteur d'écriture
        close(fd[1]); // fermer le descripteur d'écriture
        execlp("ls", "ls", NULL); // exécute le programme 'ls'
        std::cerr << "execlp failed" << std::endl;
        exit(1);
    }
    return 0;
}
```

